#!/usr/bin/env python3
# compare_fuse_rtl.py - drive the FUSE tests through z80_core via iverilog and
# compare the printed results against tests/fuse/tests.expected. The Verilog
# testbench (tests/iverilog/tb_fuse.v) is auto-generated by gen_fuse_tb.py.
import os, re, subprocess, sys

ROOT = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
GEN  = os.path.join(ROOT, "scripts/gen_fuse_tb.py")
TB_V = os.path.join(ROOT, "tests/iverilog/tb_fuse.v")
VVP  = os.path.join(ROOT, "build/tb_fuse.vvp")
EXP  = os.path.join(ROOT, "tests/fuse/tests.expected")
KNOWN_FUSE_WRONG = os.path.join(ROOT, "tests/fuse/known-fuse-wrong.txt")


def load_known_fuse_wrong(path):
    """Names whose FUSE expected values are stale vs real silicon.
    See tests/fuse/known-fuse-wrong.txt + docs/simplifications.md F1."""
    if not os.path.exists(path):
        return set()
    out = set()
    with open(path) as f:
        for line in f:
            line = line.split("#", 1)[0].strip()
            if line:
                out.add(line.split()[0])
    return out

def parse_expected(path):
    """{name: ((af,bc,de,hl,af2,bc2,de2,hl2,ix,iy,sp,pc,wz),
              (i,r,iff1,iff2,im,halted,ts), [(addr, [bytes...]), ...])}"""
    out = {}
    with open(path) as f:
        text = f.read()
    blocks = re.split(r"\n\s*\n", text.strip())
    for blk in blocks:
        lines = [ln for ln in blk.split("\n") if ln.strip()]
        if not lines: continue
        name = lines[0].strip()
        i = 1
        # skip event lines
        while i < len(lines) and (lines[i].startswith(" ") or lines[i].startswith("\t")):
            i += 1
        if i + 1 >= len(lines): continue
        regs = tuple(int(x, 16) for x in lines[i].split()[:13])
        sp = lines[i + 1].split()
        state = (int(sp[0],16), int(sp[1],16), int(sp[2]), int(sp[3]),
                 int(sp[4]), int(sp[5]), int(sp[6]))
        mem = []
        for ln in lines[i + 2:]:
            parts = ln.split()
            if not parts: continue
            if parts[0] == "-1": break
            try:
                addr = int(parts[0], 16)
            except ValueError:
                continue
            bytes_ = []
            for p in parts[1:]:
                if p == "-1": break
                bytes_.append(int(p, 16))
            mem.append((addr, bytes_))
        out[name] = (regs, state, mem)
    return out

def parse_rtl_output(text):
    """Parse RESULT and MEM lines from the iverilog run. Returns
        {name: (regs, state, {addr: byte})}
    where cycle_count is divided by 2 (phases -> T-states)."""
    out = {}
    mems = {}
    for ln in text.splitlines():
        if ln.startswith("RESULT"):
            p = ln.split()
            # RESULT name af bc de hl af2 bc2 de2 hl2 ix iy sp pc wz i r iff1 iff2 im halted phases
            name = p[1]
            regs = tuple(int(x, 16) for x in p[2:15])
            state = (int(p[15], 16), int(p[16], 16), int(p[17]), int(p[18]),
                     int(p[19]), int(p[20]), int(p[21]) // 2)
            out[name] = (regs, state, {})
            if name not in mems: mems[name] = {}
        elif ln.startswith("MEM"):
            p = ln.split()
            name, addr, byte = p[1], int(p[2], 16), int(p[3], 16)
            mems.setdefault(name, {})[addr] = byte
    for name in list(out):
        out[name] = (out[name][0], out[name][1], mems.get(name, {}))
    return out

def main():
    # regenerate testbench, build, run
    print("regenerating testbench ...")
    subprocess.check_call(["python3", GEN])
    print("elaborating ...")
    subprocess.check_call(["iverilog", "-g2001", "-Irtl",
                           "-o", VVP,
                           "rtl/z80_alu.v", "rtl/z80_core.v",
                           "rtl/z80_pla.v", "rtl/z80_timing.v",
                           "tests/iverilog/tb_fuse.v"], cwd=ROOT)
    print("running iverilog vvp ...")
    proc = subprocess.run(["vvp", VVP], cwd=ROOT, capture_output=True, text=True)
    text = proc.stdout

    rtl  = parse_rtl_output(text)
    expd = parse_expected(EXP)
    known_wrong = load_known_fuse_wrong(KNOWN_FUSE_WRONG)
    common = set(rtl) & set(expd)

    pass_ct = 0
    fail_ct = 0
    known_ct = 0
    first_fails = []
    for name in sorted(common):
        r_regs, r_state, r_mem = rtl[name]
        e_regs, e_state, e_memlist = expd[name]
        diff = []
        if r_regs != e_regs:
            cols = ["af","bc","de","hl","af2","bc2","de2","hl2","ix","iy","sp","pc","wz"]
            for c, e_v, r_v in zip(cols, e_regs, r_regs):
                if e_v != r_v: diff.append(f"{c}=exp{e_v:04x}/got{r_v:04x}")
        sc = ["i","r","iff1","iff2","im","halted","ts"]
        for c, e_v, r_v in zip(sc, e_state, r_state):
            if e_v != r_v: diff.append(f"{c}=exp{e_v}/got{r_v}")
        # memory diff
        for addr, bytes_ in e_memlist:
            for i, eb in enumerate(bytes_):
                a = (addr + i) & 0xFFFF
                rb = r_mem.get(a, eb)   # unobserved address: assume equal
                if rb != eb: diff.append(f"M[{a:04x}]=exp{eb:02x}/got{rb:02x}")
        if not diff:
            pass_ct += 1
        elif name in known_wrong:
            known_ct += 1
        else:
            fail_ct += 1
            if len(first_fails) < 10:
                first_fails.append(f"FAIL {name}: " + " ".join(diff))

    total = len(common)
    print(f"\n=== FUSE through RTL (iverilog) ===")
    print(f"{total} tests: {pass_ct} PASS, {fail_ct} FAIL, {known_ct} known-FUSE-wrong")
    if known_ct:
        print(f"note: {known_ct} cases differ from FUSE on purpose -- see "
              "tests/fuse/known-fuse-wrong.txt")
    if first_fails:
        print("\nFailures (first 10):")
        for f in first_fails: print(" ", f)
        return 1
    return 0

if __name__ == "__main__":
    sys.exit(main())
